// src/pages/payment/PaymentScreen.jsx
import React, { useState, useContext, useEffect, useRef } from "react";
import {
  View,
  Text,
  StyleSheet,
  Pressable,
  TextInput,
  ScrollView,
  ActivityIndicator,
  Alert,
  Platform,
} from "react-native";
import { AppContext } from "../../../App";
import { useTranslation } from "../../i18n";
import Header from "../../components/Header";
import { 
  initiatePayment, 
  checkPaymentStatus, 
  storePaymentInfo, 
  getPaymentInfo,
  isPaymentCompleted,
  getPaymentCompletionStatus 
} from "../../services/paymentService";

const COLORS = {
  primary: "#14B8A6",
  secondary: "#7C3AED",
  background: "#F7F9FA",
  card: "#FFFFFF",
  textDark: "#1C1C1E",
  textMuted: "#6B7280",
  error: "#DC2626",
  success: "#16A34A",
  warning: "#F59E0B",
  border: "#E5E7EB",
};

export default function PaymentScreen({ navigation, route }) {
  const { verification, setVerification } = useContext(AppContext);
  const { t } = useTranslation();

  const [selectedProvider, setSelectedProvider] = useState(null);
  const [phoneNumber, setPhoneNumber] = useState("");
  const [loading, setLoading] = useState(false);
  const [paymentStatus, setPaymentStatus] = useState(null);
  const [paymentInfo, setPaymentInfo] = useState(null);
  const [checkingStatus, setCheckingStatus] = useState(false);
  const statusCheckInterval = useRef(null);

  const verificationId = verification?.verificationId;
  const amount = 500; // FCFA

  useEffect(() => {
    // Check if payment is already completed for this verification
    const checkExistingPayment = async () => {
      if (!verificationId) {
        console.log('❌ No verification ID found');
        return;
      }

      console.log('🔍 Checking for existing payments for verification:', verificationId);

      // First check if we have payment info in AsyncStorage
      const existingPayment = await getPaymentInfo(verificationId);

      if (existingPayment) {
        console.log('📋 Found existing payment:', existingPayment);

        setPaymentInfo(existingPayment);
        setPhoneNumber(existingPayment.phoneNumber);

        // Map payment method back to provider
        const provider = existingPayment.paymentMethod === 'MOMO_CM' ? 'MTN' : 'ORANGE';
        setSelectedProvider(provider);
        setPaymentStatus(existingPayment.status);

        // Always verify with API for the most current status
        console.log('🔄 Verifying payment status with API...');
        const completionStatus = await getPaymentCompletionStatus(verificationId);

        if (completionStatus.completed) {
          console.log('✅ Payment already completed!');
          setPaymentStatus('SUCCESSFULL');

          // Update payment info with current status
          if (completionStatus.paymentInfo) {
            setPaymentInfo(completionStatus.paymentInfo);
          }

          // Update verification context
          setVerification(prev => ({
            ...prev,
            payment: {
              verified: true,
              orderId: completionStatus.orderId,
              amount: amount,
              method: provider,
              timestamp: new Date().toISOString()
            }
          }));
        } else if (completionStatus.status === 'PENDING') {
          console.log('⏳ Payment is still pending, starting status checking...');
          setPaymentStatus('PENDING');
          // Start checking payment status immediately
          startStatusChecking(existingPayment.orderId);
        } else {
          console.log('ℹ️ Payment status:', completionStatus.status);
          setPaymentStatus(completionStatus.status);
        }
      } else {
        console.log('📝 No existing payment found for this verification');
      }
    };

    checkExistingPayment();

    return () => {
      // Cleanup interval on unmount
      if (statusCheckInterval.current) {
        clearInterval(statusCheckInterval.current);
        console.log('🧹 Cleaned up status check interval');
      }
    };
  }, [verificationId]);

  const startStatusChecking = (orderId) => {
    if (statusCheckInterval.current) {
      clearInterval(statusCheckInterval.current);
    }

    console.log('🔄 Starting status checking for order:', orderId);

    // Check immediately first
    checkPaymentStatusPolling(orderId);

    // Then set up interval for continuous checking
    statusCheckInterval.current = setInterval(async () => {
      await checkPaymentStatusPolling(orderId);
    }, 5000); // Check every 5 seconds
  };

  const checkPaymentStatusPolling = async (orderId) => {
    if (!orderId) return;

    try {
      console.log('🔄 Checking payment status for order:', orderId);
      setCheckingStatus(true);

      const result = await checkPaymentStatus(orderId);
      if (result.success) {
        const newStatus = result.data.status;
        console.log('📊 New payment status:', newStatus);

        if (newStatus !== paymentStatus) {
          setPaymentStatus(newStatus);

          // Update local storage
          if (paymentInfo) {
            const updatedPayment = { ...paymentInfo, status: newStatus };
            setPaymentInfo(updatedPayment);
            await storePaymentInfo(verificationId, updatedPayment);
          }

          // If payment is successful, clear interval and show success message
          if (newStatus === 'SUCCESSFULL') {
            console.log('✅ Payment successful!');
            if (statusCheckInterval.current) {
              clearInterval(statusCheckInterval.current);
            }

            // Automatically update verification context with payment info
            setVerification(prev => ({
              ...prev,
              payment: {
                verified: true,
                orderId: orderId,
                amount: amount,
                method: selectedProvider,
                timestamp: new Date().toISOString()
              }
            }));

            // Show success message
            Alert.alert(
              t("payment.successTitle"),
              t("payment.successMessage", { amount: amount.toLocaleString() }),
              [{ text: t("common.ok") }]
            );
          }

          // If payment failed or was cancelled, clear interval and show error
          if (newStatus === 'FAILED' || newStatus === 'CANCELLED') {
            console.log('❌ Payment failed or cancelled:', newStatus);
            if (statusCheckInterval.current) {
              clearInterval(statusCheckInterval.current);
            }

            Alert.alert(
              t("payment.error"),
              t("payment.paymentFailed"),
              [{ text: t("common.ok") }]
            );
          }
        }
      }
    } catch (error) {
      console.error('Error checking payment status:', error);
    } finally {
      setCheckingStatus(false);
    }
  };

  const handleProviderSelect = (provider) => {
    setSelectedProvider(provider);
  };

  const validatePhoneNumber = (number) => {
    // Cameroonian phone number validation
    const cleaned = number.replace(/\s+/g, '');

    // Format: 237XXXXXXXXX or 6XXXXXXXX or 6XXXXXXXXX
    const cameroonRegex = /^(237)?[6|2]\d{8}$/;

    // Check if it starts with 237 (country code) or local number
    if (cleaned.startsWith('237')) {
      return cleaned.length === 12 && cameroonRegex.test(cleaned);
    } else if (cleaned.startsWith('6') || cleaned.startsWith('2')) {
      return cleaned.length === 9 && cameroonRegex.test(`237${cleaned}`);
    }

    return false;
  };

  const handlePayment = async () => {
    if (!selectedProvider) {
      Alert.alert(t("payment.error"), t("payment.selectProvider"));
      return;
    }

    if (!phoneNumber.trim()) {
      Alert.alert(t("payment.error"), t("payment.enterPhoneNumber"));
      return;
    }

    if (!validatePhoneNumber(phoneNumber)) {
      Alert.alert(t("payment.error"), t("payment.invalidPhoneNumber"));
      return;
    }

    if (!verificationId) {
      Alert.alert(t("payment.error"), t("payment.noVerificationId"));
      return;
    }

    setLoading(true);

    try {
      // Format phone number for Gloswitch (needs to include country code)
      let formattedPhone = phoneNumber.replace(/\s+/g, '');
      if (!formattedPhone.startsWith('237')) {
        formattedPhone = `237${formattedPhone}`;
      }

      // Map provider to Gloswitch payment method
      const paymentMethod = selectedProvider === 'MTN' ? 'MOMO_CM' : 'OM_CM';

      const result = await initiatePayment(formattedPhone, paymentMethod, verificationId);

      if (result.success) {
        const paymentData = {
          orderId: result.data.orderId,
          paymentToken: result.data.paymentToken,
          phoneNumber: formattedPhone,
          paymentMethod: paymentMethod,
          status: result.data.status,
          timestamp: new Date().toISOString()
        };

        // Store payment info
        await storePaymentInfo(verificationId, paymentData);
        setPaymentInfo(paymentData);
        setPaymentStatus(result.data.status);

        // Start checking payment status IMMEDIATELY without waiting for user to click OK
        console.log('🔄 Starting immediate status checking for order:', result.data.orderId);
        startStatusChecking(result.data.orderId);

        // Show alert but don't wait for user response
        Alert.alert(
          t("payment.paymentInitiated"),
          t("payment.confirmOnPhone", { amount: amount.toLocaleString(), provider: selectedProvider }),
          [
            {
              text: t("common.ok"),
              onPress: () => {
                // Optional: You can add any additional logic here if needed
                console.log('✅ User acknowledged payment prompt');
              }
            }
          ]
        );
      } else {
        Alert.alert(t("payment.error"), result.error || t("payment.initiationFailed"));
      }
    } catch (error) {
      console.error('Payment error:', error);
      Alert.alert(t("payment.error"), t("payment.networkError"));
    } finally {
      setLoading(false);
    }
  };

  const handleContinue = () => {
    // Check if payment is completed before allowing navigation
    if (paymentStatus === 'SUCCESSFULL') {
      // Store payment verification in app context
      setVerification(prev => ({
        ...prev,
        payment: {
          verified: true,
          orderId: paymentInfo?.orderId,
          amount: amount,
          method: selectedProvider,
          timestamp: new Date().toISOString()
        }
      }));

      navigation.navigate("vehicle_admin_info");
    } else {
      Alert.alert(t("payment.error"), t("payment.waitForConfirmation"));
    }
  };

  const handleBack = () => {
    navigation.navigate("find_immatriculation_or_chasis_number_screen");
  };

  const isPhoneNumberValid = validatePhoneNumber(phoneNumber);
  const isFormValid = selectedProvider && isPhoneNumberValid && verificationId;
  const isPaymentSuccessful = paymentStatus === 'SUCCESSFULL';
  const isPaymentPending = paymentStatus === 'PENDING';
  const isPaymentAlreadyCompleted = paymentStatus === 'SUCCESSFULL';

  return (
    <View style={styles.screen}>
      <Header />

      <ScrollView contentContainerStyle={styles.scroll} keyboardShouldPersistTaps="handled">
        <Pressable style={styles.backButton} onPress={handleBack}>
          <Text style={styles.backIcon}>←</Text>
        </Pressable>

        <View style={styles.header}>
          <Text style={styles.title}>
            {isPaymentAlreadyCompleted ? t("payment.alreadyPaidTitle") : t("payment.title")}
          </Text>
          <Text style={styles.subtitle}>
            {isPaymentAlreadyCompleted 
              ? t("payment.alreadyPaidMessage")
              : t("payment.subtitle")}
          </Text>

          {!isPaymentAlreadyCompleted && (
            <View style={styles.amountCard}>
              <Text style={styles.amountLabel}>{t("payment.amount")}</Text>
              <Text style={styles.amountValue}>{amount.toLocaleString()} FCFA</Text>
              {/* <Text style={styles.amountHint}>{t("payment.amountHint")}</Text> */}
            </View>
          )}
        </View>

        {/* Only show payment form if not already paid */}
        {!isPaymentAlreadyCompleted ? (
          <>
            {/* Payment Status Display */}
            {paymentStatus && (
              <View style={[
                styles.statusCard,
                isPaymentSuccessful && styles.statusCardSuccess,
                isPaymentPending && styles.statusCardPending,
                paymentStatus === 'FAILED' && styles.statusCardError
              ]}>
                <Text style={[
                  styles.statusText,
                  isPaymentSuccessful && styles.statusTextSuccess,
                  isPaymentPending && styles.statusTextPending,
                  paymentStatus === 'FAILED' && styles.statusTextError
                ]}>
                  {isPaymentSuccessful ? t("payment.statusSuccess") :
                   isPaymentPending ? t("payment.statusPending") :
                   paymentStatus === 'FAILED' ? t("payment.statusFailed") :
                   paymentStatus}
                </Text>
                {isPaymentPending && (
                  <Text style={styles.statusHint}>{t("payment.statusHint")}</Text>
                )}
              </View>
            )}

            {/* Provider Selection */}
            <View style={styles.card}>
              <Text style={styles.cardTitle}>{t("payment.selectProvider")}</Text>

              <View style={styles.providerContainer}>
                <Pressable
                  style={[
                    styles.providerButton,
                    selectedProvider === 'MTN' && styles.providerButtonSelected,
                  ]}
                  onPress={() => handleProviderSelect('MTN')}
                >
                  <View style={styles.providerContent}>
                    <View style={[styles.providerIcon, { backgroundColor: '#FFCC00' }]}>
                      <Text style={styles.providerIconText}>M</Text>
                    </View>
                    <View style={styles.providerInfo}>
                      <Text style={styles.providerName}>MTN Mobile Money</Text>
                      <Text style={styles.providerHint}>{t("payment.mtnHint")}</Text>
                    </View>
                    {selectedProvider === 'MTN' && (
                      <View style={styles.selectedIndicator}>
                        <Text style={styles.selectedIcon}>✓</Text>
                      </View>
                    )}
                  </View>
                </Pressable>

                <Pressable
                  style={[
                    styles.providerButton,
                    selectedProvider === 'ORANGE' && styles.providerButtonSelected,
                  ]}
                  onPress={() => handleProviderSelect('ORANGE')}
                >
                  <View style={styles.providerContent}>
                    <View style={[styles.providerIcon, { backgroundColor: '#FF6600' }]}>
                      <Text style={styles.providerIconText}>O</Text>
                    </View>
                    <View style={styles.providerInfo}>
                      <Text style={styles.providerName}>Orange Money</Text>
                      <Text style={styles.providerHint}>{t("payment.orangeHint")}</Text>
                    </View>
                    {selectedProvider === 'ORANGE' && (
                      <View style={styles.selectedIndicator}>
                        <Text style={styles.selectedIcon}>✓</Text>
                      </View>
                    )}
                  </View>
                </Pressable>
              </View>
            </View>

            {/* Phone Number Input */}
            <View style={styles.card}>
              <Text style={styles.cardTitle}>{t("payment.phoneNumber")}</Text>
              <Text style={styles.cardHint}>{t("payment.phoneNumberHint")}</Text>

              <TextInput
                value={phoneNumber}
                onChangeText={(text) => {
                  // Format as user types
                  const cleaned = text.replace(/\D/g, '');
                  let formatted = cleaned;

                  // Format for better readability
                  if (cleaned.length > 0) {
                    if (cleaned.startsWith('237')) {
                      formatted = `237 ${cleaned.slice(3, 6)} ${cleaned.slice(6, 9)} ${cleaned.slice(9)}`;
                    } else if (cleaned.length <= 3) {
                      formatted = cleaned;
                    } else if (cleaned.length <= 6) {
                      formatted = `${cleaned.slice(0, 3)} ${cleaned.slice(3)}`;
                    } else {
                      formatted = `${cleaned.slice(0, 3)} ${cleaned.slice(3, 6)} ${cleaned.slice(6, 9)}`;
                    }
                  }

                  setPhoneNumber(formatted.trim());
                }}
                placeholder="6XX XXX XXX"
                placeholderTextColor={COLORS.textMuted}
                keyboardType="phone-pad"
                maxLength={15}
                style={[
                  styles.input,
                  phoneNumber && !isPhoneNumberValid && styles.inputError,
                  phoneNumber && isPhoneNumberValid && styles.inputValid
                ]}
              />

              {phoneNumber && !isPhoneNumberValid && (
                <Text style={styles.errorText}>{t("payment.invalidPhoneNumber")}</Text>
              )}
              {phoneNumber && isPhoneNumberValid && (
                <Text style={styles.validText}>{t("payment.validPhoneNumber")}</Text>
              )}
            </View>

            {/* Action Buttons */}
            {!isPaymentSuccessful ? (
              <Pressable
                onPress={handlePayment}
                disabled={!isFormValid || loading || isPaymentPending}
                style={[
                  styles.primaryButton,
                  (!isFormValid || loading || isPaymentPending) && styles.buttonDisabled,
                ]}
              >
                {loading ? (
                  <ActivityIndicator color="#FFFFFF" />
                ) : isPaymentPending ? (
                  <View style={styles.buttonContent}>
                    <ActivityIndicator color="#FFFFFF" size="small" />
                    <Text style={styles.buttonText}>{t("payment.waitingConfirmation")}</Text>
                  </View>
                ) : (
                  <Text style={styles.buttonText}>{t("payment.payNow").replace("{amount}", amount.toLocaleString())}</Text>
                )}
              </Pressable>
            ) : (
              <Pressable
                onPress={handleContinue}
                style={styles.successButton}
              >
                <Text style={styles.buttonText}>{t("payment.continueToNext")}</Text>
              </Pressable>
            )}
          </>
        ) : (
          // Show success state if already paid
          <View style={[styles.statusCard, styles.statusCardSuccess]}>
            <Text style={[styles.statusText, styles.statusTextSuccess]}>
              ✅ {t("payment.statusSuccess")}
            </Text>
            <Text style={styles.statusHint}>
              {t("payment.successMessage", { amount: amount.toLocaleString() })}
            </Text>

            {/* Show payment details */}
            {paymentInfo && (
              <View style={styles.paymentDetails}>
                <Text style={styles.detailText}>
                  Order ID: <Text style={styles.detailValue}>{paymentInfo.orderId}</Text>
                </Text>
                <Text style={styles.detailText}>
                  Paid with: <Text style={styles.detailValue}>
                    {paymentInfo.paymentMethod === 'MOMO_CM' ? 'MTN Mobile Money' : 'Orange Money'}
                  </Text>
                </Text>
                <Text style={styles.detailText}>
                  Phone: <Text style={styles.detailValue}>{paymentInfo.phoneNumber}</Text>
                </Text>
                <Text style={styles.detailText}>
                  Date: <Text style={styles.detailValue}>
                    {new Date(paymentInfo.timestamp).toLocaleDateString()}
                  </Text>
                </Text>
              </View>
            )}

            {/* Continue button for already paid */}
            <Pressable
              onPress={handleContinue}
              style={[styles.successButton, { marginTop: 16 }]}
            >
              <Text style={styles.buttonText}>{t("payment.continueToNext")}</Text>
            </Pressable>
          </View>
        )}

        {/* Verification ID Display */}
        {verificationId && !isPaymentAlreadyCompleted && (
            <></>
        //   <View style={styles.infoCard}>
        //     <Text style={styles.infoText}>
        //       {t("payment.verificationId")}: <Text style={styles.infoValue}>{verificationId}</Text>
        //     </Text>
        //   </View>
        )}

        {/* Payment Instructions - Only show if not already paid */}
        {!isPaymentAlreadyCompleted && (
          <View style={styles.instructionsCard}>
            <Text style={styles.instructionsTitle}>{t("payment.instructionsTitle")}</Text>
            <Text style={styles.instructionsText}>
              {t("payment.instructions")}
            </Text>
          </View>
        )}

        <View style={{ height: 40 }} />
      </ScrollView>
    </View>
  );
}

